<h5 class="mb-3">Órdenes de Servicio</h5>
<table class="table table-hover"><tr><th>Orden</th><th>Código seguimiento</th><th>Cliente</th><th>Prioridad</th><th>Total</th><th>Estado pago</th><th>Estado servicio</th></tr><?php foreach($orders as $o): ?><tr><td><?= e($o['order_number']) ?></td><td><?= e($o['public_tracking_code']) ?></td><td><?= e($o['customer']) ?></td><td><?= e($o['priority']) ?></td><td>$<?= number_format((float)$o['estimated_total'],0,',','.') ?></td><td><?= e($o['payment_status']) ?></td><td><span class="badge bg-info"><?= e($o['status_name']) ?></span></td></tr><?php endforeach; ?></table>
